190→/**
191→ * brain system end-session
192→ * Called by SessionEnd hook.
193→ */
194→export async function runEndSession(): Promise<void> {
195→  const config = await requireConfig();
196→  const client = new BrainHttpClient(config);
197→  const cwd = process.cwd();
198→  const cached = await getDirCacheEntry(cwd);
199→
200→  if (!cached) return; // No project mapped — nothing to end
201→
202→  try {
203→    // Read stdin (Claude Code pipes Stop hook JSON)
204→    let stdinText = "";
205→    try {
206→      const chunks: Buffer[] = [];
207→      for await (const chunk of Bun.stdin.stream()) {
208→        chunks.push(Buffer.from(chunk));
209→      }
210→      stdinText = Buffer.concat(chunks).toString("utf-8").trim();
211→    } catch {
212→      // stdin not available or empty
213→    }
214→
215→    // Parse the summary payload
216→    let summary = "Session ended without summary";
217→    let decisionsMade: string[] | undefined;
218→    let questionsAsked: string[] | undefined;
219→    let tasksProgressed: Array<{ task_id: string; from_status: string; to_status: string }> | undefined;
220→    let filesChanged: Array<{ path: string; change_type: string }> | undefined;
221→    let observationsLogged: string[] | undefined;
222→    let subtasksCreated: string[] | undefined;
223→
224→    if (stdinText) {
225→      const parsed = JSON.parse(stdinText) as Record<string, unknown>;
226→      if (parsed.decision === "block") {
227→        const reason = typeof parsed.reason === "string" ? parsed.reason : "Stop hook returned block decision";
228→        throw new Error(`Session end blocked: ${reason}`);
229→      }
230→      if (parsed.decision !== "approve") {
231→        throw new Error("Stop hook payload must include decision=\"approve\" or decision=\"block\"");
232→      }
233→      if (typeof parsed.summary !== "string" || parsed.summary.trim().length === 0) {
234→        throw new Error("Stop hook payload must include a non-empty string summary");
235→      }
236→      summary = parsed.summary.trim();
237→
238→      if (parsed.decisions_made !== undefined) {
239→        if (!Array.isArray(parsed.decisions_made) || !parsed.decisions_made.every((v) => typeof v === "string")) {
240→          throw new Error("decisions_made must be an array of string ids");
241→        }
242→        decisionsMade = parsed.decisions_made;
243→      }
244→
245→      if (parsed.questions_asked !== undefined) {
246→        if (!Array.isArray(parsed.questions_asked) || !parsed.questions_asked.every((v) => typeof v === "string")) {
247→          throw new Error("questions_asked must be an array of string ids");
248→        }
249→        questionsAsked = parsed.questions_asked;
250→      }
251→
252→      if (parsed.tasks_progressed !== undefined) {
253→        if (!Array.isArray(parsed.tasks_progressed)) {
254→          throw new Error("tasks_progressed must be an array");
255→        }
256→        tasksProgressed = parsed.tasks_progressed.map((entry) => {
257→          if (!entry || typeof entry !== "object") {
258→            throw new Error("tasks_progressed entries must be objects");
259→          }
260→          const row = entry as Record<string, unknown>;
261→          if (
262→            typeof row.task_id !== "string" ||
263→            typeof row.from_status !== "string" ||
264→            typeof row.to_status !== "string"
265→          ) {
266→            throw new Error("tasks_progressed entries must include string task_id, from_status, and to_status");
267→          }
268→          return {
269→            task_id: row.task_id,
270→            from_status: row.from_status,
271→            to_status: row.to_status,
272→          };
273→        });
274→      }
275→
276→      if (parsed.files_changed !== undefined) {
277→        if (!Array.isArray(parsed.files_changed)) {
278→          throw new Error("files_changed must be an array");
279→        }
280→        filesChanged = parsed.files_changed.map((entry) => {
281→          if (!entry || typeof entry !== "object") {
282→            throw new Error("files_changed entries must be objects");
283→          }
284→          const row = entry as Record<string, unknown>;
285→          if (typeof row.path !== "string" || typeof row.change_type !== "string") {
286→            throw new Error("files_changed entries must include string path and change_type");
287→          }
288→          if (!["created", "modified", "deleted"].includes(row.change_type)) {
289→            throw new Error("files_changed.change_type must be one of: created, modified, deleted");
290→          }
291→          return { path: row.path, change_type: row.change_type };
292→        });
293→      }
294→
295→      if (parsed.observations_logged !== undefined) {
296→        if (!Array.isArray(parsed.observations_logged) || !parsed.observations_logged.every((v) => typeof v === "string")) {
297→          throw new Error("observations_logged must be an array of string ids");
298→        }
299→        observationsLogged = parsed.observations_logged;
300→      }
301→
302→      if (parsed.subtasks_created !== undefined) {
303→        if (!Array.isArray(parsed.subtasks_created) || !parsed.subtasks_created.every((v) => typeof v === "string")) {
304→          throw new Error("subtasks_created must be an array of string ids");
305→        }
306→        subtasksCreated = parsed.subtasks_created;
307→      }
308→    }
309→
310→    // Get session_id from cache, or create a session as fallback
311→    let sessionId = cached.session_id;
312→    if (!sessionId) {
313→      const session = await client.sessionStart({
314→        agent: "claude-code",
315→        project_id: cached.project_id,
316→      });
317→      sessionId = session.session_id;
318→    }
319→
320→    await client.sessionEnd({
321→      session_id: sessionId,
322→      summary,
323→      decisions_made: decisionsMade,
324→      questions_asked: questionsAsked,
325→      tasks_progressed: tasksProgressed,
326→      files_changed: filesChanged,
327→      observations_logged: observationsLogged,
328→      subtasks_created: subtasksCreated,
329→    });
330→
331→    // Clear session_id from cache
332→    await setDirCacheEntry(cwd, { ...cached, session_id: undefined });
333→  } catch (error) {
334→    console.error(`Brain: Failed to end session: ${error instanceof Error ? error.message : error}`);
335→  }
336→}
