338→// ---------------------------------------------------------------------------
339→// Format helpers
340→// ---------------------------------------------------------------------------
341→
342→function formatContextPacket(packet: unknown): string {
343→  const p = packet as Record<string, unknown>;
344→  const lines: string[] = [];
345→
346→  lines.push("# Brain Knowledge Graph Context\n");
347→
348→  // Workspace & project
349→  const ws = p.workspace as { id: string; name: string } | undefined;
350→  const proj = p.project as { id: string; name: string; status: string; description?: string } | undefined;
351→  if (ws) lines.push(`Workspace: ${ws.name}`);
352→  if (proj) {
353→    lines.push(`Project: ${proj.name} (${proj.status})`);
354→    if (proj.description) lines.push(`Description: ${proj.description}`);
355→  }
356→  lines.push("");
357→
358→  // Task scope
359→  const taskScope = p.task_scope as Record<string, unknown> | undefined;
360→  if (taskScope) {
361→    const task = taskScope.task as { id: string; title: string; status: string; description?: string };
362→    lines.push(`## Current Task: ${task.title} [${task.status}]`);
363→    if (task.description) lines.push(task.description);
364→
365→    const subtasks = taskScope.subtasks as Array<{ id: string; title: string; status: string }>;
366→    if (subtasks?.length) {
367→      lines.push("\nSubtasks:");
368→      for (const s of subtasks) lines.push(`  - [${s.status}] ${s.title}`);
369→    }
370→
371→    const siblings = taskScope.sibling_tasks as Array<{ id: string; title: string; status: string }>;
372→    if (siblings?.length) {
373→      lines.push("\nSibling tasks:");
374→      for (const s of siblings) lines.push(`  - [${s.status}] ${s.title}`);
375→    }
376→    lines.push("");
377→  }
378→
379→  // Decisions
380→  const decisions = p.decisions as { confirmed: unknown[]; provisional: unknown[]; contested: unknown[] } | undefined;
381→  if (decisions) {
382→    if (decisions.contested.length > 0) {
383→      lines.push("## CONTESTED DECISIONS (conflicts — do not proceed without human input)");
384→      for (const d of decisions.contested as Array<{ summary: string; rationale?: string }>) {
385→        lines.push(`  - ${d.summary}${d.rationale ? ` — ${d.rationale}` : ""}`);
386→      }
387→      lines.push("");
388→    }
389→
390→    if (decisions.confirmed.length > 0) {
391→      lines.push("## Confirmed Decisions (follow these)");
392→      for (const d of decisions.confirmed as Array<{ summary: string }>) {
393→        lines.push(`  - ${d.summary}`);
394→      }
395→      lines.push("");
396→    }
397→
398→    if (decisions.provisional.length > 0) {
399→      lines.push("## Provisional Decisions (follow but flag for review)");
400→      for (const d of decisions.provisional as Array<{ summary: string }>) {
401→        lines.push(`  - ${d.summary}`);
402→      }
403→      lines.push("");
404→    }
405→  }
406→
407→  // Active tasks
408→  const tasks = p.active_tasks as Array<{ title: string; status: string; priority?: string }> | undefined;
409→  if (tasks?.length) {
410→    lines.push("## Active Tasks");
411→    for (const t of tasks) {
412→      lines.push(`  - [${t.status}]${t.priority ? ` (${t.priority})` : ""} ${t.title}`);
413→    }
414→    lines.push("");
415→  }
416→
417→  // Open questions
418→  const questions = p.open_questions as Array<{ text: string; status: string }> | undefined;
419→  if (questions?.length) {
420→    lines.push("## Open Questions");
421→    for (const q of questions) {
422→      lines.push(`  - [${q.status}] ${q.text}`);
423→    }
424→    lines.push("");
425→  }
426→
427→  // Recent changes
428→  const changes = p.recent_changes as Array<{ entity_type: string; entity_name: string; change_type: string; changed_at: string }> | undefined;
429→  if (changes?.length) {
430→    lines.push("## Recent Changes");
431→    for (const c of changes) {
432→      lines.push(`  - [${c.entity_type}] ${c.entity_name} — ${c.change_type}`);
433→    }
434→    lines.push("");
435→  }
436→
437→  // Observations
438→  const observations = p.observations as Array<{ text: string; severity: string }> | undefined;
439→  if (observations?.length) {
440→    lines.push("## Observations");
441→    for (const o of observations) {
442→      lines.push(`  - [${o.severity}] ${o.text}`);
443→    }
444→    lines.push("");
445→  }
446→
447→  // Active agent sessions (cross-agent awareness)
448→  type ActiveSession = {
449→    agent: string;
450→    started_at: string;
451→    task?: { id: string; title: string };
452→    provisional_decisions: Array<{ summary: string }>;
453→    observations: Array<{ text: string; severity: string }>;
454→  };
455→  const activeSessions = p.active_sessions as ActiveSession[] | undefined;
456→  if (activeSessions?.length) {
457→    lines.push("## Active Agent Sessions");
458→    for (const s of activeSessions) {
459→      const ago = formatTimeAgo(s.started_at);
460→      lines.push(`  - ${s.agent} (started ${ago})`);
461→      if (s.task) {
462→        lines.push(`    Working on: ${s.task.title}`);
463→      }
464→      if (s.provisional_decisions.length > 0) {
465→        lines.push("    Provisional decisions:");
466→        for (const d of s.provisional_decisions) {
467→          lines.push(`      - ${d.summary}`);
468→        }
469→      }
470→      if (s.observations.length > 0) {
471→        lines.push("    Observations:");
472→        for (const o of s.observations) {
473→          lines.push(`      - [${o.severity}] ${o.text}`);
474→        }
475→      }
476→    }
477→    lines.push("");
478→  }
479→
480→  return lines.join("\n");
481→}
482→
483→function formatTimeAgo(isoString: string): string {
484→  const diff = Date.now() - new Date(isoString).getTime();
485→  const minutes = Math.floor(diff / 60000);
486→  if (minutes < 1) return "just now";
487→  if (minutes < 60) return `${minutes}m ago`;
488→  const hours = Math.floor(minutes / 60);
489→  if (hours < 24) return `${hours}h ago`;
490→  return `${Math.floor(hours / 24)}d ago`;
491→}
